import{_ as o,o as t,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"61. Long Service Leave","description":"","frontmatter":{"title":"61. Long Service Leave","eba":"Health Allied & Managers Admin 2021-2025","topics":["leave","long-service-leave","preliminary"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/leave/61-long-service-leave.md","filePath":"ebas/has-managers-admin/common-terms/leave/61-long-service-leave.md"}'),a={name:"ebas/has-managers-admin/common-terms/leave/61-long-service-leave.md"};function i(s,e,l,p,c,m){return t(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="_61-long-service-leave" tabindex="-1">61. Long Service Leave <a class="header-anchor" href="#_61-long-service-leave" aria-label="Permalink to &quot;61. Long Service Leave&quot;">​</a></h1><p><strong>61.1</strong> Part 1 - General</p><p><strong>(a)</strong> Scope This clause is split into 3 parts:</p><p><strong>(i)</strong> Part 1 (Clause 61.1) explains the scope of this clause and includes defined terms used across each Part.</p><p><strong>(ii)</strong> Part 2 (Clause 61.2) sets out the long service leave entitlement of Employees employed as a Group A Employee or Group B Employee (as defined below) at the time they take a period of long service leave or their employment ceases.</p><p><strong>(iii)</strong> Part 3 (Clause 61.3) contains a series of common provisions that apply in respect of all Employees.</p><p><strong>(b)</strong> Definitions The following meanings shall apply to the terms referred to below for the purposes of this clause unless a contrary intention is apparent:</p><p><strong>(i)</strong> Allowable period of absence means five weeks in addition to the total period of paid annual, long service or personal leave which the Employee actually receives on termination or for which the Employee is paid in lieu.</p><p><strong>(ii)</strong> Group A Employee means, for the purpose of this clause 61, an Employee employed in one of the following roles or classifications: <strong>(A)</strong> in Part 1 of <a href="/eba/ebas/has-managers-admin/schedules/2d-classification-structure-health-allied-services.html">Schedule 2D</a>; <strong>(B)</strong> in Part 1 of <a href="/eba/ebas/has-managers-admin/schedules/3d-classification-structure-managers-and-administrative-workers.html">Schedule 3D</a> in Grades 1A -10; <strong>(C)</strong> in Part 2 of <a href="/eba/ebas/has-managers-admin/schedules/3d-classification-structure-managers-and-administrative-workers.html">Schedule 3D</a> in Grades 1A - 7; or <strong>(D)</strong> as a Dental Assistant</p><p><strong>(iii)</strong> Group B Employee means, for the purpose of this clause 61, an Employee employed in Part 1 of <a href="/eba/ebas/has-managers-admin/schedules/3d-classification-structure-managers-and-administrative-workers.html">Schedule 3D</a> in Grade 11</p><p><strong>(iv)</strong> Institution means any Employer, hospital or benevolent home, community health centre, Society or Association: <strong>(A)</strong> named in Schedule 1 of this Agreement; or <strong>(B)</strong> that was registered and subsidised pursuant to the Health Services Act 1988 (Vic) or the former Hospital and Charities Act 1958 (Vic); or <strong>(C)</strong> the Cancer Institute constituted under the Cancer Act 1958 (Vic); or <strong>(D)</strong> the Fairfield Hospital Board; or <strong>(E)</strong> the Bush Nursing Association, <strong>(F)</strong> and successors thereto.</p><p><strong>(v)</strong> LSL Act means the Long Service Leave Act 2018 (Vic).</p><p><strong>(vi)</strong> Month means a calendar month.</p><p><strong>(vii)</strong> Pay means remuneration for an employee’s normal weekly hours of work calculated at the employee’s ordinary time rate of pay provided in <a href="/eba/ebas/has-managers-admin/schedules/2b-wage-rates-health-allied-services.html">Schedules 2B</a> or 3B at the time the leave is taken or (if the Employee dies before the completion of leave so taken) as at the time of the Employee&#39;s death; and will include any allowances usually paid, and will also include the amount of any increase to the Employee’s ordinary time rate of pay which occurred during the period of leave as from the date of such increase operates provided that where accommodation is made available to an Employee during his/her period of leave.</p><p>If an Employee does not have normal weekly hours of work, Pay is calculated in accordance with section 16 of the LSL Act.</p><p><strong>(viii)</strong> Service means employment with an Employer, Institution or Statutory Body.</p><p><strong>(ix)</strong> Statutory Body means the Hospital and Charities Commission of Victoria, the Health Commission of Victoria, the Department of Health and Human Services and the NMBA, and successors thereto.</p><p><strong>(x)</strong> Transfer of business occurs in the circumstances described at section 311 of the Act.</p><p><strong>61.2</strong> Part 2 - Long service leave for Group A and Group B Employees</p><p><strong>(a)</strong> Application of Part 2 This part (clause 61.2) applies to Group A Employees and Group B Employees only.</p><p><strong>(i)</strong> Entitlement Subject to clause 61.2(c) Employees are entitled to: <strong>(A)</strong> six months&#39; long service leave with Pay on completion of fifteen years of Continuous Service; and <strong>(B)</strong> thereafter an additional two months&#39; long service leave with Pay on completion of each additional five years of Continuous Service.</p><p><strong>(ii)</strong> Subject to clause 61.2(c)(iii) below and 61.2(c)(iv), an entitlement under clause 61.2(a)(i) may be taken in advance on a pro rata basis if the Employee has accrued Continuous Service of at least: <strong>(A)</strong> 10 years as at the date on which this Agreement is approved by the Fair Work Commission; or <strong>(B)</strong> from 1 July 2021, 9 years; or <strong>(C)</strong> from 1 July 2022, 8 years; or <strong>(D)</strong> from 1 July 2023, 7 years.</p><p><strong>(b)</strong> Calculating Continuous Service</p><p><strong>(i)</strong> Definitions: <strong>(A)</strong> Continuous Service means continuous Service with the same Employer plus any prior Service of six months or more with one or more Institutions or Statutory Bodies.</p><p><strong>(B)</strong> Continuous Casual Employment means, for the purpose of clause 61.2(b)(ii), a period or periods of casual Service that are taken to be continuous, because one of the following applies: i. the period starting at the end of a particular instance of employment and ending at the start of another particular instance of employment did not exceed either the allowable period of absence, or 12 weeks (whichever is greater); or ii. the Employee had been employed by an Employer on a regular and systematic basis and the Employee had a reasonable expectation of being re-engaged by the same Employer; or iii. the gap between engagements was due to the terms of engagement of the casual Employee; or iv. the gap between engagements was caused by seasonal factors; or v. the Employee and Employer agreed, before the start of an absence, to treat the employment as continuous despite the absence.</p><p><strong>(ii)</strong> Periods that count towards Continuous Service Service or prior Service as a Group A Employee or Group B Employee during the following periods will be deemed to be continuous and will count as Continuous Service for the purpose of subclause (61.2(a)(i)): <strong>(A)</strong> an absence from work on any form of paid leave (e.g. annual leave, personal leave, long service leave and paid parental leave); <strong>(B)</strong> any interruption or ending of employment by the Employer if made with the intention of avoiding obligations in respect of long service leave or annual leave; <strong>(C)</strong> any absence on account of illness or injury arising out of or in the course of the employment for a period during which an Employee is receiving accident pay (see <a href="/eba/ebas/has-managers-admin/common-terms/wages/33-accident-pay.html">clause 33</a>); <strong>(D)</strong> any absence from employment on defence service in accordance with section 8 of the Defence Reserve Service (Protection) Act 2001 (Cth);</p><p><strong>(E)</strong> a period of absence on community service leave under the Act; <strong>(F)</strong> in the case of unpaid absences not otherwise referenced in this subclause, subject to clause 61.2(g): i. any unpaid leave that is authorised in advance in writing by the Employer to count as service; or ii. up to (but not including) 30 June 2020, any unpaid absence from work of not more than fourteen days in any year on account of illness or injury; or iii. on and from 1 July 2020: 1. any period of unpaid leave taken on account of illness or injury; 2. a period of Parental Leave, including Parental Leave that is extended under <a href="/eba/ebas/has-managers-admin/common-terms/leave/59-parental-leave.html">clause 59</a>; and 3. the first 52 weeks of any other type of unpaid leave not specifically referenced in this subclause 61.2(b)(ii) and iv. periods of Continuous Casual Employment with an Employer, Statutory Body or Institution, save that if long service leave was already taken or paid in lieu in respect of any such period, no further benefit to long service leave will arise in respect of that period.</p><p><strong>(iii)</strong> Periods that do not break Continuous Service, but do not count towards Continuous Service Unless otherwise agreed in writing in advance between the Employer and Employee, the following periods do not break Continuous Service but do not count towards an employee&#39;s Continuous Service for the purpose of calculating the employee&#39;s long service leave entitlement: <strong>(A)</strong> any authorised period of unpaid leave not referred to in sub-clause 61.2(b)(ii); <strong>(B)</strong> subject to the requirements of the Act, any interruption arising directly or indirectly from an industrial dispute;</p><p><strong>(C)</strong> any period between the engagement with one Institution or Statutory Body and another provided it is less than the allowable period of absence from employment; <strong>(D)</strong> the dismissal of an employee if the employee is re- employed by the same Employer within a period not exceeding two months from the date of such dismissal; <strong>(E)</strong> up to (but not including) the commencement date of this Agreement, any absence on account of injury arising out of or in the course of her/his employment not covered by a period in which an Employee is receiving accident make up pay or other paid leave; <strong>(F)</strong> any unpaid absence of not more than 24 months taken by a Group A Employee or Group B Employee for the sole purpose of undertaking a course of study related to nursing or midwifery where the written approval of the Employer is given; and <strong>(G)</strong> any absence from work of a Group A Employee or Group B Employee for a period not exceeding twelve months in respect of any pregnancy not covered by 61.2(b)(ii)(A) or (ii)(F).</p><p><strong>(c)</strong> Taking of leave</p><p><strong>(i)</strong> When leave is to be taken Long service leave will be granted by the Employer within six months from the date of the entitlement arising under clause 61.2(a)(i) save that: <strong>(A)</strong> long service leave may be postponed to a mutually agreeable date; <strong>(B)</strong> if agreement cannot be reached: i. for Group A Employees, the date will be determined by a member of the Fair Work Commission provided that such a determination will not require long service leave to commence before six months from the date of such determination; and ii. for Group B Employees the date may be determined by the Employee save that the Employer may refuse the date nominated by an Employee on reasonable business grounds.</p><p><strong>(C)</strong> Employees of the Royal Women&#39;s Hospital or Royal Children&#39;s Hospital classified in a role described in i. become entitled to long service leave; and ii. do not take such leave within two years, may otherwise be required to take an amount of leave to reduce their entitlement to no more than three (3) months, unless deferment of the leave has been approved in writing by the Employer; and <strong>(D)</strong> leave the subject of approval or grant under clause 61.2(c)(iii) shall be taken in accordance with the terms of the application or agreement.</p><p><strong>(ii)</strong> How leave is to be taken Long service leave may be taken in any number of periods of no less than one week (in the case of a Group A Employee) or one day (in the case of a Group B Employee) as agreed between the Employee and the Employer or as otherwise agreed as part of a transition to retirement.</p><p><strong>(iii)</strong> Long service leave in advance <strong>(A)</strong> If an Employee has completed ten years&#39; Continuous Service, an Employer may, by agreement with the Employee, grant long service leave in advance on a pro rata basis. <strong>(B)</strong> Supplementary to subclause 61.2(c)(iii)(A), and subject to subclause 61.2(c)(iii)(C): i. if a Group A Employee requests to take long service leave on a pro rata basis under clause 61.2(c)(iii)(A), the Employer must grant the Employee&#39;s request to take long service leave as soon as practicable after receiving the request unless the Employer has reasonable business grounds for refusing the request; and/or ii. for Group B Employees, an Employer may, by agreement with the Employee, grant long service leave in advance on a pro rata basis at any time. <strong>(C)</strong> If an Employee takes long service leave in advance and the Employee&#39;s employment ends before the entitlement to the leave would otherwise have accrued:</p><p>iii. the Employer may, from whatever amount is payable to the Employee upon termination, deduct the amount paid to the Employee for the leave in respect of which the Employee was not entitled, if: 1. in the case of a Group A Employee, the termination was for serious and wilful misconduct; or 2. in the case of a Group B Employee, the Employee had accrued less than 7 years&#39; Continuous Service with the Employer as at the termination date; and 3. the relevant period of service will not count as a period in respect of which long service leave has already been taken (or paid in lieu) for the purpose of clause 61.2(b)(ii) above (Periods that count towards Continuous Service for Group A and Group B Employees).</p><p><strong>(iv)</strong> Flexible taking of leave An Employee may, subject to approval by the Employer, convert their long service leave entitlement in one of the following ways: <strong>(A)</strong> taking double the period of approved long service leave at half Pay; or <strong>(B)</strong> taking half of the leave accrued at double Pay for the period of approved leave. Flexible taking of long service leave does not affect an Employee&#39;s period of continuous service recognised. For example, an employee taking 12 months of long service leave at half pay will, for the purpose of calculating continuous service, have six months of continuous service recognised.</p><p><strong>(d)</strong> Payment on termination of employment</p><p><strong>(i)</strong> Interpretation For the purposes of this clause 61.2(d), termination of employment has its ordinary meaning, provided that: <strong>(A)</strong> it is taken to occur upon conversion from full-time or</p><p><strong>(B)</strong> it is not taken to occur at the cessation of each shift as a casual Employee.</p><p><strong>(ii)</strong> Basic entitlement at termination of employment Except where an election is made under clause 61.2(d)(iii) below, an Employee is entitled to payment in lieu of untaken long service leave upon termination of employment (calculated at one thirtieth of the period of Continuous Service) if, as at the termination date: <strong>(A)</strong> in the case of a Group A Employee: i. the Employee has accrued at least fifteen years&#39; Continuous Service with the Employer; or the Employee has an entitlement to pro rata long service leave under clause 61.2(c)(iii) and was not terminated for serious and wilful misconduct; or <strong>(B)</strong> in the case of a Group B Employee, the Employee has accrued at least 7 years&#39; Continuous Service with the Employer.</p><p><strong>(iii)</strong> Election for payment of entitlement or transfer of entitlement at termination <strong>(A)</strong> This subclause applies to the following Employees: i. Group A Employees who have an entitlement to be paid pro rata long service leave under clause 61.2(c)(iii) (who therefore have less than fifteen years&#39; accrued Continuous Service with an Employer); and ii. Group B Employees who have at least seven years&#39; accrued Continuous Service with an Employer. <strong>(B)</strong> An Employee to whom subclause 61.2(d)(iii)(A) applies who intends to be re-employed by another Institution or Statutory Body, may: i. request in writing that payment for accrued long service leave be deferred until after the Employee’s allowable period of absence (as defined above) has expired; and ii. where the Employee notifies the initial Employer in writing within the allowable period of absence that the Employee has been employed by such an employer, and the re-employment meets the criteria set out in in subclause 61.2(d)(iii)(D)</p><p>below, the initial Employer is no longer required to make payment to the Employee in respect of such service. <strong>(C)</strong> Where the notice referred to at 61.2(d)(iii)ii. is not provided prior to or within the allowable period of absence the Employer will, upon the expiration of the allowable period of absence, make payment in lieu of long service leave as per subclause 61.2(d)(ii). <strong>(D)</strong> For the purposes of this subclause, re-employment by another Institution or Statutory Body means employment other than as a Group C Employee.</p><p><strong>(iv)</strong> Payment in lieu of long service leave on the death of an Employee Where an Employee dies while still in the employ of the Employer, payment in lieu of long service leave will be made to the Employee’s personal representative in accordance with clause 61.2(d)(ii) above.</p><p><strong>(v)</strong> No entitlement arising for periods of leave already taken For the removal of doubt, where an Employee makes an election under clause 61.2(d)(iii) such that their previous Service is recognised by the new Employer, the Employee’s previous Employer is no longer liable to make any payment in lieu of that employee’s service.</p><p><strong>(e)</strong> Public holidays and Accrued Days Off See also <a href="/eba/ebas/has-managers-admin/common-terms/leave/69-public-holidays.html">clause 69</a> (Public Holidays) and 47 (Accrued Days Off). Long service leave is inclusive of any public holiday or ADO occurring during the period when leave is taken.</p><p><strong>(f)</strong> Proof of sufficient aggregate of service The onus of proving a sufficient aggregate of service to support a claim for any long service leave entitlement will at all times rest upon the Employee concerned. A certificate in the following form will constitute acceptable proof: CERTIFICATE OF SERVICE</p><p>[Name of Institution] [date]</p><p>This is to certify that [Name of Employee] has been employed by this institution/society/board for a period of [years/months/etc.] from [date] to [date].</p><p>Specify hereunder full details of any additional service with a different Institution or Statutory Body that was recognised by [Name of Institution]:</p><p>…………………………………………………..</p><p>Specify hereunder full details of paid leave, unpaid leave or absences (including whether any such period constitutes Continuous Service), and periods represented by a payment made in lieu of leave or a transfer of leave upon termination of employment:</p><p>…………………………………………………..</p><p>Specify hereunder full details of long service leave granted during service or on termination:</p><p>…………………………………………………..</p><p>Signed ……………………………[Stamp of institution]</p><p><strong>(g)</strong> Transitional Arrangements for Parental Leave taken after 1 November 2018 and before the commencement date of this Agreement Note 1: Unpaid Parental Leave taken prior to 1 November 2018 does not count as Continuous Service unless otherwise agreed, per clause 61.2(b)(iii)(F). Note 2: Unpaid Parental Leave taken after the commencement date of this Agreement will constitute Continuous Service, per clause 61.2(b)(iii)(F).</p><p><strong>(i)</strong> As an exception to clause 61.2(b)(iii)(F), an Employee who took a period of unpaid Parental Leave that included any commencement date of this agreement (inclusive) may make an application to the Employer to have that service recognised for Long Service Leave purposes. The Employer will approve the application and provide to the Employee an updated Certificate of Service reflecting the adjusted service arrangements.</p><p><strong>(ii)</strong> An Employee electing to make an application under 61.2(g)(i) must make the application to the Employer no later than 6 months of the following (whichever occurs last): <strong>(A)</strong> the date on which this Agreement commences; or <strong>(B)</strong> the date on which the Employee returns to work after the qualifying period of unpaid Parental Leave.</p><p><strong>(iii)</strong> This clause 61.2(g) shall also apply to an Employee in respect of a former Employer if the Employee took a qualifying unpaid period of Parental Leave under this clause while employed by that former Employer.</p><p><strong>(h)</strong> Service before 30 December 1964 Notwithstanding clause 61.2(b)(ii)for the purpose of determining the entitlement of an Employee classified:</p><p><strong>(i)</strong> in Part 1 of <a href="/eba/ebas/has-managers-admin/schedules/3d-classification-structure-managers-and-administrative-workers.html">Schedule 3D</a> in Grades 1 -10; or</p><p><strong>(ii)</strong> in Part 2 of <a href="/eba/ebas/has-managers-admin/schedules/3d-classification-structure-managers-and-administrative-workers.html">Schedule 3D</a> in Grades 1 - 7, in respect of a period of employment beginning before 30 December 1964 and ending after the said date, the period of Service completed before 30 December 1964 will be reduced by one quarter.</p><p><strong>61.3</strong> Part 3 - Common conditions applicable to all Employees</p><p><strong>(a)</strong> Payment for period of leave</p><p><strong>(i)</strong> Payment will be made in one of the following ways: <strong>(A)</strong> in full advance when the Employee commences his/her leave; <strong>(B)</strong> at the same time as payment would have been made if the Employee had remained on duty; or <strong>(C)</strong> in any other way agreed between the Employer and the Employee.</p><p><strong>(ii)</strong> Where an Employee has been paid in advance, and an increase occurs in the ordinary time rate of pay during the period of long service leave taken, the Employee will be entitled to receive payment of the amount of any increase in pay at the completion of such leave.</p><p><strong>(b)</strong> Records The Employer will keep a long service leave record for each Employee, containing particulars of service, leave taken and payments made.</p><p><strong>(c)</strong> Transfer of business Where a Transfer of Business occurs, an Employee who worked with the old Employer and who continues in the service of the new Employer will be entitled to count their service with the old Employer as service with the new Employer for the purposes of this clause.</p><p><strong>(d)</strong> Concurrent Service</p><p><strong>(i)</strong> Subject to subclause 61.3(d)(ii), concurrent service with two or more Employers remains separate and distinct.</p><p><strong>(ii)</strong> If a Group A or Group B Employee transfers from an Employer (the first Employer) to another employer (the new Employer) into an equivalent role, but retains concurrent employment with the first Employer as a casual Employee, then the Employee&#39;s service with the first Employer may</p><p>transfer to the new Employer (despite the Employee remaining employed with the first Employer), if: <strong>(A)</strong> the Employee does not have an entitlement to take long service leave under clause 61.2(a)(i); <strong>(B)</strong> the Employee has not already taken or been paid in lieu of long service leave in respect of the relevant period; and <strong>(C)</strong> either: i. the Employee notifies the first Employer of the transfer in accordance with sub-clause 61.2(d)(iii) (Election for payment of entitlement or transfer of entitlement at termination); or ii. the second Employer otherwise confirms in writing to the first Employer that the period of service has been so recognised (for the removal of doubt, if the second Employer determines to recognise the Employee&#39;s service with the first Employer, it must provide written notification of its determination to the first Employer).</p><p><strong>(iii)</strong> If an Award-entitled Employee&#39;s long service leave entitlement is transferred in accordance with subclause 61.3(d)(ii): <strong>(A)</strong> the first Employer will no longer be liable for the service, and the long service leave liability for the service as an Award-entitled Employee with the first Employer will transfer to the new Employer; <strong>(B)</strong> any casual service that occurs with the first Employer after the transfer referred to in (61.3(d)(iii)(A)) above will be considered separate and distinct service on and from the date on which the Employee commenced employment with the new Employer, provided that: i. the qualifying period required to accrue an entitlement to long service leave with the first Employer does not reset (that is, the Employee&#39;s prior service with the first Employer can be counted when calculating any future entitlement to long service leave with the first Employer); ii. no benefit to long service leave will arise with the first Employer in respect of the prior period of employment with the first Employer; and</p><p>iii. the Employee&#39;s prior service with the first Employer is disregarded when calculating the Employee&#39;s normal weekly hours with the first Employer (e.g. for the purpose of sections 16 and 17 of the LSL Act).</p><p><strong>(iv)</strong> If the Employee is not entitled to transfer their service from the first Employer to the new Employer, or does not take the steps required in sub-clause 61.2(d)(iii) within the allowable period of absence, the first Employer will make payment in lieu of long service leave for the Continuous Service with the first Employer in accordance with clause 61.2(d)(ii) (Basic entitlement at termination of employment). Example 1:</p><p>A Group A Employee is employed at the same time by Employer 1, and Employer 2.</p><p>The Group A Employee accrues service towards long service leave at each of Employer 1 and Employer 2.</p><p>If the Employee had been employed by Employer 1 for 11 years and Employer 2 for 6 years, the Employee can take LSL from Employer 1, but would need to continue working at Employer 2 until sufficient Continuous Service had accrued.</p><p>If the Employee resigned from both Employer 1 and Employer 2, and went to work for Employer 3, the Employee could:</p><p><strong>(a)</strong> transfer the 6 years&#39; service with Employer 2 to Employer 3; and</p><p><strong>(b)</strong> have the accrued LSL from the 11 years&#39; service with Employer 1 paid out in lieu on termination.</p><p>Example 2:</p><p>A Group B Employee has worked for Employer 1 for 6 years. The Employee commences employment with Employer 2 as a full-time Employee. To take up this opportunity, the Employee ceases permanent employment with Employer 1.</p><p>However, the Employee commences a casual employment relationship with Employer 1 within 12 weeks after resigning from their permanent position with Employer 1.</p><p>The Employee:</p><p><strong>(a)</strong> could transfer the 6 years&#39; service with Employer 1 to Employer 2, and would be eligible to take LSL with Employer 2 once sufficient Continuous Service had accrued (taking into account the transferred service); and</p><p><strong>(b)</strong> could also take LSL on a pro rata basis with Employer 1 after sufficient Continuous Service had accrued, save that no entitlement would arise in respect of the prior 6 years&#39; service that had been transferred to Employer 2.</p><p><strong>(e)</strong> Savings</p><p><strong>(i)</strong> Clauses 61.2(d)(iii), 61.2(d)(v), 61.2(e), 61.2(g)(ii)and 61.3(d)(ii) shall not apply to a Group B Employee, unless the Industrial Division of the Magistrates Court provides an opinion that determines generally the rights of applicable Employees under this Agreement under sub-section 23(2) of the LSL Act that the long service leave entitlements provided by this Agreement are more favourable than those provided by the LSL Act.</p><p><strong>(ii)</strong> The Unions and VHIA must make an application to the Magistrates Court under section 24 of the LSL Act for an opinion referred to in section 61.3(e)(i) as soon as reasonably practicable after the Agreement has been approved by the Fair Work Commission.</p><p><strong>(iii)</strong> No Employee shall otherwise suffer any detriment as a result of the operation of this clause to their entitlement to long service leave existing immediately prior to the coming into force of this clause.</p><p>Plain language terms: LSL, long service, LSL entitlement.</p>',92)])])}const u=o(a,[["render",i]]);export{d as __pageData,u as default};
